import { AppBar, Box, Button, Divider, Drawer, IconButton, List, ListItem, ListItemButton, ListItemText, Toolbar, Typography } from "@mui/material";
import React, { useState } from "react";
import MenuIcon from '@mui/icons-material/Menu';
import { colors } from "../media/colorsModule";
import { Link } from "react-router-dom";
import logo from './media/logo.png';
import styles from './media/header.module.scss';


export const Header:React.FC = () => {
	const [isBtnOpen, setIsBtnOpen] = useState('none')
	const navItems = [
    {link: 'method', title: 'Метод'},
    {link: 'price', title: 'Цены'},
    {link: 'equipment', title: 'Оборудование'},
    {link: 'languages', title: 'Языки'}
  ];
	const [mobileOpen, setMobileOpen] = React.useState(false);
	const handleDrawerToggle = () => {
		setMobileOpen((prevState) => !prevState);
	  };
	const drawer = (
		<Box className={styles.drawer} onClick={handleDrawerToggle} sx={{ textAlign: 'center', width: 240, height: '100%' }}>
		  <Typography variant="h6" sx={{ my: 2 }}>
			MUI
		  </Typography>
		  <Divider />
		  <List className={styles.linkListDrawer}>
			{navItems.map((item) => (
			  <ListItem key={item} disablePadding>
				<ListItemButton sx={{ textAlign: 'center' }}>
				  <Link to={`/${item.link}`}>
          {item.title}
				  </Link>
        </ListItemButton>
			  </ListItem>
			))}
		  </List>
		</Box>
	  );

	return (
		<AppBar component="nav">
        <Toolbar className={styles.header}>
          <Link className={styles.logoLink} to='/'>
            <img src={logo} alt="logo" />
          </Link>
          <Box sx={{ flexGrow: 1 }} />
          <IconButton
            aria-label="open drawer"
            edge="start"
			      onClick={handleDrawerToggle}
            sx={{ mr: 2, display: { sm: 'none' }, color: colors.color_grey}}
          >
            <MenuIcon />
          </IconButton>
          <Box sx={{ display: { xs: 'none', sm: 'block' } }}>
            <Button className={styles.link} onClick={() => {setIsBtnOpen(isBtnOpen === 'none' ? 'flex' : 'none')}}>
              {'Терапия'}
            </Button>
            <Box className={styles.linksBlock} sx={{ display: isBtnOpen}}>
              <Link to={'/method'}>Метод</Link>
              <Link to={'/oborud'}>Оборудование</Link>
            </Box>
            <Button  className={styles.link}>
              <Link to={'/'}>
                {'Цены'}
              </Link>
            </Button>
            <Button  className={styles.link}>
              <Link to={'/'}>
                {'Иностранные языки'}
              </Link>
            </Button>
          </Box>
        </Toolbar>
		<Drawer
          className={styles.drawerWrapper}
          variant="temporary"
          open={mobileOpen}
          onClose={handleDrawerToggle}
          ModalProps={{
            keepMounted: true,
          }}
        >
          {drawer}
        </Drawer>
      </AppBar>
	)
}
